<template><view class="page"><view class="tabs"><view :class="{on:type==='video'}" @click="setType('video')">视频</view><view :class="{on:type==='article'}" @click="setType('article')">图文</view></view><view class="card" v-for="c in items" :key="c.id" @click="go(c)"><text class="title">{{c.title}}</text><text class="muted">{{c.levelText||'权限以后端返回为准'}} {{c.paid?'已购买':(c.price?'付费':'免费')}}</text></view></view></template><script setup lang="ts">import { ref } from 'vue';import { onLoad,onShow } from '@dcloudio/uni-app';import { contentApi } from '@/services/content';import { listOf } from '@/utils/format';const type=ref('video'),items=ref<any[]>([]);async function load(){items.value=listOf((await contentApi.list({type:type.value})).data)}function setType(t:string){type.value=t;load()}function go(c:any){uni.navigateTo({url:'/pages/content/detail/index?id='+c.id})}onLoad((o:any)=>{if(o.type)type.value=o.type});onShow(load)</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.tabs{display:flex;padding:20rpx;gap:16rpx}.tabs view{flex:1;background:#fff;text-align:center;padding:22rpx;border-radius:999rpx}.tabs .on{background:#2b1207;color:#f0bf55}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}.title{display:block;font-size:34rpx;font-weight:900}.muted{display:block;color:#8d8175;font-size:24rpx;margin-top:12rpx}</style>
